"use strict";parserFactory.register("peachpuff.in",()=>new PeachpuffParser);class PeachpuffParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.querySelector("ul.lcp_catlist");return util.hyperlinksToChapterList(t)}findContent(e){return e.querySelector(".kenta-article-content")}extractTitleImpl(e){return e.querySelector("h1")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,".category-post-dropdown-container, .code-block"),super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector("h1")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".kenta-article-content p")]}}